{
  "name": "sample-repo",
  "version": "1.0.0",
  "description": "A sample repository for testing harvx golden tests",
  "main": "dist/app.js",
  "scripts": {
    "build": "tsc",
    "test": "jest",
    "lint": "eslint src/"
  },
  "dependencies": {
    "express": "^4.18.0"
  },
  "devDependencies": {
    "typescript": "^5.0.0",
    "jest": "^29.0.0"
  }
}

package api

import (
	"encoding/json"
	"fmt"
	"net/http"
)

// Handler holds the dependencies for HTTP request handling.
type Handler struct {
	version string
}

// NewHandler creates a new Handler with the given version string.
func NewHandler(version string) *Handler {
	return &Handler{version: version}
}

// HealthCheck returns a 200 OK with version information.
func (h *Handler) HealthCheck(w http.ResponseWriter, r *http.Request) {
	resp := map[string]string{
		"status":  "ok",
		"version": h.version,
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

// ListUsers returns a JSON array of user summaries.
func (h *Handler) ListUsers(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	fmt.Fprintf(w, `{"users":[],"total":0}`)
}

package api

import (
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestHealthCheck(t *testing.T) {
	h := NewHandler("1.0.0")
	req := httptest.NewRequest(http.MethodGet, "/health", nil)
	rec := httptest.NewRecorder()

	h.HealthCheck(rec, req)

	if rec.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d", rec.Code)
	}
}

func TestListUsers(t *testing.T) {
	h := NewHandler("1.0.0")
	req := httptest.NewRequest(http.MethodGet, "/users", nil)
	rec := httptest.NewRecorder()

	h.ListUsers(rec, req)

	if rec.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d", rec.Code)
	}
}

export function greet(name: string): string {
  return `Hello, ${name}!`;
}

package auth

import "fmt"

// CheckAuth verifies authentication credentials.
func CheckAuth() bool {
	fmt.Println("checking auth")
	return true
}

// ValidateToken checks if a JWT token is valid.
func ValidateToken(token string) bool {
	return len(token) > 0
}

package auth

import "testing"

func TestCheckAuth(t *testing.T) {
	if !CheckAuth() {
		t.Fatal("expected true")
	}
}

package main

import (
	"fmt"
	"sample-repo/src/auth"
)

func main() {
	fmt.Println("Sample app")
	auth.CheckAuth()
}

package models

// User represents an authenticated user in the system.
type User struct {
	ID       int    `json:"id"`
	Email    string `json:"email"`
	Name     string `json:"name"`
	Role     string `json:"role"`
	IsActive bool   `json:"is_active"`
}

// NewUser creates a new User with the given email and name.
func NewUser(email, name string) *User {
	return &User{
		Email:    email,
		Name:     name,
		Role:     "user",
		IsActive: true,
	}
}

// IsAdmin reports whether the user has admin privileges.
func (u *User) IsAdmin() bool {
	return u.Role == "admin"
}

import { greet } from "./app";

describe("greet", () => {
  it("should greet by name", () => {
    expect(greet("World")).toBe("Hello, World!");
  });
});

export function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

package main

import "fmt"

func main() {
	fmt.Println("Hello, world!")
}
